import{_ as o,o as l,c as a,ah as i}from"./chunks/framework.Bi9enVNS.js";const p=JSON.parse('{"title":"Virtual Log Trace 是什么","description":"","frontmatter":{},"headers":[],"relativePath":"intro/what-is-vlt.md","filePath":"intro/what-is-vlt.md","lastUpdated":1774205896000}'),t={name:"intro/what-is-vlt.md"};function r(c,e,d,s,n,h){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="virtual-log-trace-是什么" tabindex="-1">Virtual Log Trace 是什么 <a class="header-anchor" href="#virtual-log-trace-是什么" aria-label="Permalink to &quot;Virtual Log Trace 是什么&quot;">​</a></h1><p>Virtual Log Trace，简称 VLT，是一个协议优先的可视化日志追踪参考实现。它不是“日志平台概念图”，而是一个已经把协议、上传入口、查询接口、示例发送器和前端工作台都串起来的可运行代码库。</p><h2 id="它在解决什么问题" tabindex="-1">它在解决什么问题 <a class="header-anchor" href="#它在解决什么问题" aria-label="Permalink to &quot;它在解决什么问题&quot;">​</a></h2><p>很多系统的日志能产出 <code>trace_id</code>，但缺少统一上传协议、缺少来源建模、也缺少把“同一条 Trace 的多来源日志”用直观视图串起来的最小闭环。VLT 解决的是这个闭环问题：</p><ul><li>上传侧：定义统一的批次协议与校验规则</li><li>存储侧：把每条日志归一化到统一模型</li><li>查询侧：按日志、Trace、Timeline、Topology、Sources 多种视角取数</li><li>展示侧：用一个 Trace Workbench 联动这些视角</li></ul><h2 id="当前仓库里已经有什么" tabindex="-1">当前仓库里已经有什么 <a class="header-anchor" href="#当前仓库里已经有什么" aria-label="Permalink to &quot;当前仓库里已经有什么&quot;">​</a></h2><ul><li><code>proto/vlt/common/v1/common.proto</code></li><li><code>proto/vlt/logs/v1/logs.proto</code></li><li><code>proto/vlt/ingest/v1/ingest.proto</code></li><li><code>POST /v1/logs</code> 摄取入口</li><li><code>GET /v1/logs/search</code>、<code>GET /v1/traces/{trace_id}</code>、<code>GET /v1/traces/{trace_id}/timeline</code>、<code>GET /v1/traces/{trace_id}/topology</code>、<code>GET /v1/sources</code></li><li>Go 服务端 <code>cmd/vlt-server</code></li><li>Go sender <code>cmd/vlt-sender</code></li><li>React Trace Workbench <code>web/</code></li></ul><h2 id="它适合拿来做什么" tabindex="-1">它适合拿来做什么 <a class="header-anchor" href="#它适合拿来做什么" aria-label="Permalink to &quot;它适合拿来做什么&quot;">​</a></h2><ul><li>验证你自己的日志上传协议设计</li><li>给 demo / 原型项目补一套真实可跑的 Trace 浏览能力</li><li>在继续做持久化、权限、索引之前，先把字段和交互闭环跑顺</li><li>作为团队讨论“来源建模”和“拓扑推导”时的具体参考对象</li></ul><h2 id="它不是什么" tabindex="-1">它不是什么 <a class="header-anchor" href="#它不是什么" aria-label="Permalink to &quot;它不是什么&quot;">​</a></h2><ul><li>不是一套完整的生产级 observability 平台</li><li>不是持久化日志存储系统，当前只提供内存存储</li><li>不是 OpenTelemetry 全量替代品，当前协议是 VLT 自己的 <code>v1</code></li><li>不是自动发现系统依赖图的引擎，当前 topology 由 Trace 内时间相邻来源段推导</li></ul><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>README.md</code></li><li><code>proto/vlt/*/v1/*.proto</code></li><li><code>cmd/vlt-server/main.go</code></li><li><code>web/src/App.jsx</code></li></ul>',13)])])}const m=o(t,[["render",r]]);export{p as __pageData,m as default};
